-- Initial schema for the products DB, matching the Good and Manufacturer entity mappings.
-- Also seeds the manufacturer table (previously inserted manually into the dev DB).

CREATE TABLE good (
    id           bigint GENERATED BY DEFAULT AS IDENTITY,
    name         text,
    description  text,
    category     text,
    image        bytea,
    price_kopeck bigint  NOT NULL,
    quantity     integer NOT NULL,
    CONSTRAINT good_pkey PRIMARY KEY (id)
);

CREATE TABLE manufacturer (
    id          bigint GENERATED BY DEFAULT AS IDENTITY,
    name        text,
    contacts    text,
    description text,
    CONSTRAINT manufacturer_pkey PRIMARY KEY (id)
);

CREATE TABLE good_manufacturer (
    good_id         bigint NOT NULL,
    manufacturer_id bigint NOT NULL,
    CONSTRAINT fk_good_manufacturer_good FOREIGN KEY (good_id) REFERENCES good (id),
    CONSTRAINT fk_good_manufacturer_manufacturer FOREIGN KEY (manufacturer_id) REFERENCES manufacturer (id)
);

