INSERT INTO public.manufacturer (id, contacts, description, name) VALUES (1, 'ДП "Поло-Електрообладнання", вул. Кульженків, 12Б (літ. А, А1), 04082, Kyiv, Тел.: +38 044 536-19-22', 'Hager здобув ім''я професіонала в сфері електроінсталяцій для житлової та комерційної нерухомості і це не просто так.
