INSERT INTO public.manufacturer (id, contacts, description, name) VALUES (3, 'Україна, м. Кропивницький, вул. Героїв Маріуполя, 106-Ж, 25004, тел. +38 050-567-57-57', 'Компанія Аллєгро-опт була заснована в 1996 році, спочатку займалася виробництвом і продажем аудіо та відео касет.
