INSERT INTO public.manufacturer (id, contacts, description, name) VALUES (4, 'Україна, м. Київ, пр. Степана Бандери, 13в літ. А, 04073, тел. +38 044-538-14-70', 'Schneider Electric - компанія, яка пропонує енергетичні рішення, які виходять за рамки стандартних концепцій і гарантують доступ до енергії для промислових підприємств, об’єктів цивільного та житлового будівництва, а також різноманітних центрів в котрих обробляють данні.', 'Schneider');
INSERT INTO public.manufacturer (id, contacts, description, name) VALUES (5, 'Україна, вулиця Вікентія Хвойки, 21, 121, Київ, 04655, тел. +38 096-985-52-75', 'Сьогодні марка DigiTOP отримала широку популярність вже далеко за межами України, вона активно продається в Східній Європі, Туреччині, Казахстані та інших країнах ближнього і дальнього зарубіжжя.
Як невеликій фірмі, створеній парою ентузіастів, вдалося перетворитися в компанію, яка налічує понад 1000 бізнес-партнерів в 10-ти країнах? У самій основі створення бренду DigiTOP лежала потреба звичайної людини в якісному продукті, і ми ніколи не відступали від принципу «роби, як для себе».', 'DigiTOP');
INSERT INTO public.manufacturer (id, contacts, description, name) VALUES (6, 'Україна, м.Київ вул. Новозабарська, буд. 23, тел. +380981808454', 'ТОВ «Дженерал Енерджі Україна», висловлює Вам свою повагу, і повідомляємо, що наша компанія стала партнером і імпортером всесвітньо відомого виробника електрообладнання низької і середньої напруги компанії АВВ.
Протягом 15 років наша компанія була імпортером і представником іншого виробника електрообладнання, компанії General Electric (GE). У 2017 році частина бізнесу GE (обладнання до 35 кВ) придбала компанія АВВ, що дозволило нам стати частиною команди АВВ.', 'ABB');
INSERT INTO public.manufacturer (id, contacts, description, name) VALUES (7, 'м. Івано-Франківськ, 76011, тел. +38 (067) 333-51-84', 'Наше підприємство вже понад 30 років на ринку кабельно-провідникової продукції. За цей невеликий період наш завод зарекомендував себе надійним партнером та професіоналом своєї справи. Особливу увагу на ЗЗКМ приділяють системі менеджменту якості.
Система менеджменту якості ЗЗКМ сьогодні стала в повному розумінні слова системою управління підприємством.
Орієнтація на споживача, лідерство на всіх рівнях управління, залучення персоналу в досягненні загальних завдань і цілей, процесний підхід в практичній діяльності підприємства, націленість на постійні поліпшення результативності системи менеджменту якості, прийняття рішення, спираючись на факти, їх оцінку і всебічний аналіз, а, також, оптимізація управлінських рішень у взаєминах з постачальниками – це ті принципи, які в наших умовах перетворюють систему менеджменту якості в систему управління підприємством.', 'Запорізький завод кольорових металів');
